   125	void nr_rrc_handle_timers(NR_UE_RRC_INST_t *rrc)
   126	{
   127	  NR_UE_Timers_Constants_t *timers = &rrc->timers_and_constants;
   128	
   129	  bool release_timer_expired = nr_timer_tick(&rrc->release_timer);
   130	  if (release_timer_expired)
   131	    handle_RRCRelease(rrc);
   132	
   133	  bool t300_expired = nr_timer_tick(&timers->T300);
   134	  if(t300_expired) {
   135	    LOG_W(NR_RRC, "Timer T300 expired! No timely response to RRCSetupRequest\n");
   136	    handle_t300_expiry(rrc);
   137	  }
   138	
   139	  bool t301_expired = nr_timer_tick(&timers->T301);
   140	  // Upon T301 expiry, the UE shall perform the actions upon going to RRC_IDLE
   141	  // with release cause 'RRC connection failure'
   142	  if(t301_expired) {
   143	    LOG_W(NR_RRC, "Timer T301 expired! No timely response to RRCReestabilshmentRequest\n");
   144	    nr_rrc_going_to_IDLE(rrc, RRC_CONNECTION_FAILURE, NULL);
   145	  }
   146	
   147	  bool t304_expired = nr_timer_tick(&timers->T304);
   148	  if(t304_expired) {
   149	    LOG_W(NR_RRC, "Timer T304 expired\n");
   150	    // TODO
   151	    // For T304 of MCG, in case of the handover from NR or intra-NR
   152	    // handover, initiate the RRC re-establishment procedure;
   153	    // In case of handover to NR, perform the actions defined in the
   154	    // specifications applicable for the source RAT.
   155	  }
   156	
   157	  bool t310_expired = nr_timer_tick(&timers->T310);
   158	  if(t310_expired) {
   159	    LOG_W(NR_RRC, "Timer T310 expired\n");
   160	    // TODO
   161	    // handle detection of radio link failure
   162	    // as described in 5.3.10.3 of 38.331
   163	    AssertFatal(false, "Radio link failure! Not handled yet!\n");
   164	  }
   165	
   166	  bool t311_expired = nr_timer_tick(&timers->T311);
   167	  if(t311_expired) {
   168	    LOG_W(NR_RRC, "Timer T311 expired! No suitable cell found in time after initiation of re-establishment\n");
   169	    // Upon T311 expiry, the UE shall perform the actions upon going to RRC_IDLE
   170	    // with release cause 'RRC connection failure'
   171	    nr_rrc_going_to_IDLE(rrc, RRC_CONNECTION_FAILURE, NULL);
   172	  }
   173	}
